from pathlib import Path
import pandas as pd

from src.utils.logger import get_logger

logger = get_logger("Metadata Updater")


# ==========================================================
# Columns generated by Stage 2
# ==========================================================

STAGE2_COLUMNS = [

    # ---------- Audio Validation ----------

    "audio_valid",
    "duration_sec",
    "sample_rate",
    "channels",
    "bit_depth",
    "rms",
    "peak",
    "silence_ratio",
    "validation_message",

    # ---------- Transcript Validation ----------

    "exists",
    "readable",
    "utf8",
    "empty",
    "duplicated",
    "characters",
    "words",
    "lines",
    "status",
    "message",

    # ---------- Pair Validation ----------

    "transcript_valid",
    "pair_valid"

]


def update_metadata(project_root: Path):

    logger.info("=" * 70)
    logger.info("Updating metadata.csv")
    logger.info("=" * 70)

    metadata_path = project_root / "metadata" / "metadata.csv"

    metadata = pd.read_csv(metadata_path)

    # ======================================================
    # Remove old Stage 2 columns (if they already exist)
    # ======================================================

    existing = [c for c in STAGE2_COLUMNS if c in metadata.columns]

    if existing:

        logger.info(f"Removing old Stage 2 columns ({len(existing)})")

        metadata.drop(columns=existing, inplace=True)

    # ======================================================
    # Load Validation Files
    # ======================================================

    audio = pd.read_csv(
        project_root / "metadata" / "audio_validation.csv"
    )

    transcript = pd.read_csv(
        project_root / "metadata" / "transcript_validation.csv"
    )

    pair = pd.read_csv(
        project_root / "metadata" / "pair_validation.csv"
    )

    # ======================================================
    # Merge Audio Validation
    # ======================================================

    metadata = metadata.merge(

        audio[[
            "pair_id",
            "audio_valid",
            "duration_sec",
            "sample_rate",
            "channels",
            "bit_depth",
            "rms",
            "peak",
            "silence_ratio",
            "validation_message"
        ]],

        on="pair_id",

        how="left"

    )

    # ======================================================
    # Merge Transcript Validation
    # ======================================================

    metadata = metadata.merge(

        transcript[[
            "pair_id",
            "exists",
            "readable",
            "utf8",
            "empty",
            "duplicated",
            "characters",
            "words",
            "lines",
            "status",
            "message"
        ]],

        on="pair_id",

        how="left"

    )

    # ======================================================
    # Merge Pair Validation
    # ======================================================

    metadata = metadata.merge(

        pair[[
            "pair_id",
            "transcript_valid",
            "pair_valid"
        ]],

        on="pair_id",

        how="left"

    )

    # ======================================================
    # Save
    # ======================================================

    metadata.to_csv(

        metadata_path,

        index=False,

        encoding="utf-8-sig"

    )

    logger.info("metadata.csv updated successfully.")

    logger.info("=" * 70)

    return metadata